import { tags } from 'decantr/tags';
import { createSignal, onMount, onDestroy } from 'decantr/state';
import { css } from 'decantr/css';
import { icon } from 'decantr/components';

code.example:
function CommandPalette({ commands, onSelect, onClose }) {
  const { div, input, span, kbd } = tags;
  const [query, setQuery] = createSignal('');
  const [selectedIndex, setSelectedIndex] = createSignal(0);

  const filteredCommands = () => {
    const q = query().toLowerCase();
    if (!q) return commands.slice(0, 10);
    return commands.filter(c =>
      c.label.toLowerCase().includes(q) || c.category?.toLowerCase().includes(q)
    ).slice(0, 10);
  };

  const handleKeyDown = (e) => {
    const filtered = filteredCommands();
    if (e.key === 'Escape') onClose();
    else if (e.key === 'ArrowDown') setSelectedIndex(Math.min(selectedIndex() + 1, filtered.length - 1));
    else if (e.key === 'ArrowUp') setSelectedIndex(Math.max(selectedIndex() - 1, 0));
    else if (e.key === 'Enter' && filtered[selectedIndex()]) {
      onSelect(filtered[selectedIndex()]);
      onClose();
    }
  };

  onMount(() => document.addEventListener('keydown', handleKeyDown));
  onDestroy(() => document.removeEventListener('keydown', handleKeyDown));

  return div({ class: css('_fixed _inset0 _flex _center _z[100] _bg[rgba(0,0,0,0.8)]'), onclick: onClose },
    div({ class: css('term-panel _w[500px] _mw[90vw] _maxh[400px] _flex _col'), onclick: (e) => e.stopPropagation() },
      div({ class: css('_flex _aic _gap2 _p2 _borderB _bordercolor[#333]') },
        icon('search', { class: css('_fgmuted') }),
        input({
          type: 'text',
          placeholder: 'Type a command...',
          value: query,
          oninput: (e) => { setQuery(e.target.value); setSelectedIndex(0); },
          class: css('_flex1 _bg[transparent] _border0 _outline0 _fggreen _mono'),
          autofocus: true
        })
      ),
      div({ class: css('_flex1 _overflow[auto]') },
        ...filteredCommands().map((cmd, i) =>
          div({
            class: css(`_flex _aic _jcsb _p2 _cursor[pointer] ${i === selectedIndex() ? '_bgmuted/20' : ''}`),
            onclick: () => { onSelect(cmd); onClose(); },
            onmouseenter: () => setSelectedIndex(i)
          },
            div({ class: css('_flex _aic _gap2') },
              icon(cmd.icon || 'terminal', { size: '14' }),
              span({}, cmd.label),
              cmd.category ? span({ class: css('_fgmuted _textsm') }, cmd.category) : null
            ),
            cmd.shortcut ? kbd({ class: css('term-hotkey _textsm _px1') }, cmd.shortcut) : null
          )
        )
      ),
      div({ class: css('_flex _aic _gap4 _p2 _borderT _bordercolor[#333] _textsm _fgmuted') },
        span({}, 'Navigate:'), kbd({}, 'arrow'), ' ',
        span({}, 'Select:'), kbd({}, 'enter'), ' ',
        span({}, 'Close:'), kbd({}, 'esc')
      )
    )
  );
}

