function MinimalPalette({ commands, onSelect, onClose }) {
  const { div, input, span } = tags;
  const [query, setQuery] = createSignal('');

  const filtered = () => commands.filter(c =>
    c.label.toLowerCase().includes(query().toLowerCase())
  ).slice(0, 5);

  return div({ class: css('_fixed _inset0 _flex _center _z[100] _bg[rgba(0,0,0,0.8)]'), onclick: onClose },
    div({ class: css('term-panel _w[400px]'), onclick: (e) => e.stopPropagation() },
      input({
        type: 'text',
        placeholder: '>',
        value: query,
        oninput: (e) => setQuery(e.target.value),
        class: css('_wfull _bg[transparent] _border0 _p2 _fggreen _mono _outline0'),
        autofocus: true
      }),
      ...filtered().map(cmd =>
        div({ class: css('_p2 _cursor[pointer] _hover:bgmuted/20'), onclick: () => { onSelect(cmd); onClose(); } },
          span({}, cmd.label)
        )
      )
    )
  );
}

